query:
-- Update describe_image questions with publicly accessible chart/graph images
-- Using Wikimedia Commons and other open-access educational chart images

UPDATE questions SET imageUrl = 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4f/Pie_chart_of_US_GHG_emissions_2020.svg/600px-Pie_chart_of_US_GHG_emissions_2020.svg.png'
WHERE taskType = 'describe_image' AND title LIKE '%Renewable%' LIMIT 1;

UPDATE questions SET imageUrl = 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b5/World_population_%28UN%29.svg/640px-World_population_%28UN%29.svg.png'
WHERE taskType = 'describe_image' AND title LIKE '%Population%' LIMIT 1;

UPDATE questions SET imageUrl = 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/51/Simple_line_graph_of_US_unemployment.svg/640px-Simple_line_graph_of_US_unemployment.svg.png'
WHERE taskType = 'describe_image' AND title LIKE '%Unemployment%' LIMIT 1;

UPDATE questions SET imageUrl = 'https://upload.wikimedia.org/wikipedia/commons/thumb/9/9e/Global_Temperature_Anomaly.svg/640px-Global_Temperature_Anomaly.svg.png'
WHERE taskType = 'describe_image' AND title LIKE '%Climate%' LIMIT 1;

-- For any remaining describe_image questions without an imageUrl, assign a sample chart
UPDATE questions SET imageUrl = 'https://upload.wikimedia.org/wikipedia/commons/thumb/1/1e/Bar_chart_of_global_internet_usage.svg/640px-Bar_chart_of_global_internet_usage.svg.png'
WHERE taskType = 'describe_image' AND (imageUrl IS NULL OR imageUrl = '') LIMIT 3;

